module top_module(
    output reg [7:0] q,
    input [7:0] d,
    input [18:0] write_address, read_address,
    input we, clk
);(* ramstyle = "M10K" *)

    reg [7:0] data_store [383999:0] ;

    always @ (posedge clk) begin
        if (we)
            data_store[write_address] <= d;
        q <= data_store[read_address]; 
    end

endmodule
